#include<stdio.h>
int main()
{
    long long int a,n,m,i,j;
    scanf("%lld%lld%lld",&n,&m,&a);
    if(n>=1&&a<=1e9&&a!=0)
    {
        if(n%a==0)
            i=n/a;
        else{
            i=n/a;
            i=i+1;
        }
        if(m%a==0)
            j=m/a;
        else{
            j=m/a;
            j=j+1;
        }
        i=i*j;
        printf("%lld",i);
    }
    return 0;
}

