use std::io;

fn main() {
    let mut string = String::new();
    io::stdin().read_line(&mut string)
        .expect("Read error!");

    let int_vec: Vec<_> = string.trim().split(' ')
        .map(|x| x.parse::<u64>().expect("Not an integer!"))
        .collect();

    if int_vec.len() != 3 {
        panic!("Bad input");
    }

    println!("{}", ((int_vec[0] as f64) / (int_vec[2] as f64)).ceil() *
                    ((int_vec[1] as f64) / (int_vec[2] as f64)).ceil() );
}
